#####################################################################################
# Terraform module examples are meant to show an _example_ on how to use a module
# per use-case. The code below should not be copied directly but referenced in order
# to build your own root module that invokes this module
#####################################################################################
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 4.11"
    }
  }

  required_version = ">= 0.14.9"

  backend "s3" {
    bucket = "$BUCKET"
    key    = "$path/to/file.tfstate"
    region = "$BUCKET_REGION"
  }
}

locals {
  s3_state_file_url = "https://$BUCKET.s3.$BUCKET_REGION.amazonaws.com/$path/to/file.tfstate"
  app_name          = "Application-${random_string.session.id}"
}

resource "random_string" "session" {
  length  = 8
  special = false
}

#tfsec:ignore:aws-dynamodb-enable-at-rest-encryption tfsec:ignore:aws-dynamodb-enable-recovery tfsec:ignore:aws-dynamodb-table-customer-key
resource "aws_dynamodb_table" "ddb_table" {
  billing_mode = "PAY_PER_REQUEST"
  name         = "DdbTable-${random_string.session.id}"

  hash_key = "key"
  attribute {
    name = "key"
    type = "N"
  }
}

#tfsec:ignore:aws-rds-encrypt-instance-storage-data tfsec:ignore:aws-rds-specify-backup-retention tfsec:ignore:aws-rds-enable-performance-insights
resource "aws_db_instance" "rds_instance" {
  allocated_storage    = 5
  engine               = "mysql"
  engine_version       = "5.7"
  instance_class       = "db.t3.micro"
  db_name              = "RDS${random_string.session.id}"
  username             = "foo"
  password             = "foobarbaz"
  parameter_group_name = "default.mysql5.7"
  skip_final_snapshot  = true
}

module "resiliencehub_app" {
  app_name = local.app_name
  source   = "../.."
  rto      = 300
  rpo      = 60
  app_components = [
    {
      app_component_name = "DynamoDBComponent"
      app_component_type = "AWS::ResilienceHub::DatabaseAppComponent"
      resources = [
        {
          resource_name            = "DynamoDBTable"
          resource_type            = "AWS::DynamoDB::Table"
          resource_identifier      = aws_dynamodb_table.ddb_table.id
          resource_identifier_type = "Native"
          resource_region          = "us-west-2"
        }
      ]
    },
    {
      app_component_name = "RdsComponent"
      app_component_type = "AWS::ResilienceHub::DatabaseAppComponent"
      resources = [
        {
          resource_name            = "RdsInstance"
          resource_type            = "AWS::RDS::DBInstance"
          resource_identifier      = aws_db_instance.rds_instance.id
          resource_identifier_type = "Native"
          resource_region          = "us-west-2"
        }
      ]
    }
  ]
  s3_state_file_url = local.s3_state_file_url
}

# tfsec:ignore:custom-custom-cus002 tfsec:ignore:aws-autoscaling-enforce-http-token-imds tfsec:ignore:aws-autoscaling-enable-at-rest-encryption tfsec:ignore:custom-custom-cus003
resource "aws_launch_configuration" "launch_conf_use1" {
  name_prefix   = "terraform-lc"
  image_id      = data.aws_ami.al2_use1.id
  instance_type = "t2.micro"

  lifecycle {
    create_before_destroy = true
  }
  provider = aws.use1
}

resource "aws_autoscaling_group" "autoscaling_group_use1" {
  name                 = "terraform-asg"
  availability_zones   = ["us-east-1a"]
  launch_configuration = aws_launch_configuration.launch_conf_use1.name
  min_size             = 1
  max_size             = 2

  lifecycle {
    create_before_destroy = true
  }
  provider = aws.use1
}

locals {
  enabled = module.this.enabled
}

module "log_group_label" {
  source  = "cloudposse/label/null"
  version = "0.25.0"

  # Allow forward slashes
  regex_replace_chars = "/[^a-zA-Z0-9-_\\/]/"

  context = module.this.context
}

resource "aws_cloudwatch_log_group" "default" {
  count             = local.enabled ? 1 : 0
  name              = module.log_group_label.id
  retention_in_days = var.retention_in_days
  tags              = module.log_group_label.tags
  kms_key_id        = var.kms_key_arn
}

resource "aws_cloudwatch_log_stream" "default" {
  count          = local.enabled && length(var.stream_names) > 0 ? length(var.stream_names) : 0
  name           = element(var.stream_names, count.index)
  log_group_name = element(aws_cloudwatch_log_group.default.*.name, 0)
}

# Upgrades to AWS DMS versions 3.4.7 and higher require that you configure AWS DMS to use VPC endpoints or use public routes.
# This requirement applies to source and target endpoints for these data stores: S3, Kinesis, Secrets Manager, DynamoDB, Amazon Redshift, and OpenSearch Service.
resource "aws_vpc_endpoint" "s3" {
  count = local.enabled ? 1 : 0

  vpc_endpoint_type = "Gateway"
  vpc_id            = local.vpc_id
  service_name      = "com.amazonaws.${var.region}.s3"
  route_table_ids   = local.route_table_ids

  tags = module.this.tags
}

module "s3_bucket" {
  source  = "cloudposse/s3-bucket/aws"
  version = "3.1.2"

  acl                          = "private"
  versioning_enabled           = false
  allow_encrypted_uploads_only = false
  allow_ssl_requests_only      = false
  force_destroy                = true
  block_public_acls            = true
  block_public_policy          = true
  ignore_public_acls           = true
  restrict_public_buckets      = true

  context = module.this.context
}

# https://aws.amazon.com/premiumsupport/knowledge-center/s3-bucket-dms-target/
# https://docs.aws.amazon.com/dms/latest/userguide/CHAP_Target.S3.html
data "aws_iam_policy_document" "dms_assume_role" {
  count = local.enabled ? 1 : 0

  statement {
    actions = ["sts:AssumeRole"]

    principals {
      identifiers = [
        "dms.amazonaws.com",
        "batchoperations.s3.amazonaws.com"
      ]
      type = "Service"
    }
  }
}

data "aws_iam_policy_document" "s3" {
  count = local.enabled ? 1 : 0

  statement {
    actions = [
      "s3:PutObject",
      "s3:PutObjectTagging",
      "s3:DeleteObject",
      "s3:InitiateReplication"
    ]

    resources = [format("%s/*", module.s3_bucket.bucket_arn)]
    effect    = "Allow"
  }

  statement {
    actions = [
      "s3:ListBucket",
      "s3:GetReplicationConfiguration",
      "s3:PutInventoryConfiguration"
    ]

    resources = [module.s3_bucket.bucket_arn]
    effect    = "Allow"
  }
}

module "s3_label" {
  source  = "cloudposse/label/null"
  version = "0.25.0"

  attributes = ["s3-access"]
  context    = module.this.context
}

resource "aws_iam_policy" "s3" {
  count = local.enabled ? 1 : 0

  name   = module.s3_label.id
  policy = join("", data.aws_iam_policy_document.s3[*].json)

  tags = module.s3_label.tags
}

resource "aws_iam_role" "s3" {
  count = local.enabled ? 1 : 0

  name               = module.s3_label.id
  assume_role_policy = join("", data.aws_iam_policy_document.dms_assume_role[*].json)

  tags = module.s3_label.tags
}

resource "aws_iam_role_policy_attachment" "s3" {
  count = local.enabled ? 1 : 0

  policy_arn = join("", aws_iam_policy.s3[*].arn)
  role       = join("", aws_iam_role.s3[*].name)
}

locals {
  enabled   = module.this.enabled
  partition = join("", data.aws_partition.current[*].partition)
}

data "aws_partition" "current" {
  count = local.enabled ? 1 : 0
}

data "aws_iam_policy_document" "dms_assume_role" {
  count = local.enabled ? 1 : 0

  statement {
    actions = ["sts:AssumeRole"]

    principals {
      identifiers = ["dms.amazonaws.com"]
      type        = "Service"
    }
  }
}

# Database Migration Service requires
# the below IAM Roles to be created before
# replication instances can be created.
# The roles should be provisioned only once per account.
# https://docs.aws.amazon.com/dms/latest/userguide/CHAP_Security.html
# https://docs.aws.amazon.com/dms/latest/userguide/CHAP_Security.html#CHAP_Security.APIRole
# https://registry.terraform.io/providers/hashicorp/aws/latest/docs/resources/dms_replication_instance
#  * dms-vpc-role
#  * dms-cloudwatch-logs-role
#  * dms-access-for-endpoint

resource "aws_iam_role" "dms_redshift_s3" {
  count = local.enabled ? 1 : 0

  assume_role_policy = join("", data.aws_iam_policy_document.dms_assume_role[*].json)
  name               = "dms-access-for-endpoint"

  tags = module.this.tags
}

resource "aws_iam_role_policy_attachment" "dms_redshift_s3" {
  count = local.enabled ? 1 : 0

  policy_arn = "arn:${local.partition}:iam::aws:policy/service-role/AmazonDMSRedshiftS3Role"
  role       = join("", aws_iam_role.dms_redshift_s3[*].name)
}

resource "aws_iam_role" "dms_cloudwatch_logs" {
  count = local.enabled ? 1 : 0

  assume_role_policy = join("", data.aws_iam_policy_document.dms_assume_role[*].json)
  name               = "dms-cloudwatch-logs-role"

  tags = module.this.tags
}

resource "aws_iam_role_policy_attachment" "dms_cloudwatch_logs" {
  count = local.enabled ? 1 : 0

  policy_arn = "arn:${local.partition}:iam::aws:policy/service-role/AmazonDMSCloudWatchLogsRole"
  role       = join("", aws_iam_role.dms_cloudwatch_logs[*].name)
}

resource "aws_iam_role" "dms_vpc_management" {
  count = local.enabled ? 1 : 0

  assume_role_policy = join("", data.aws_iam_policy_document.dms_assume_role[*].json)
  name               = "dms-vpc-role"

  tags = module.this.tags
}

resource "aws_iam_role_policy_attachment" "amazon_dms_vpc_management" {
  count = local.enabled ? 1 : 0

  policy_arn = "arn:${local.partition}:iam::aws:policy/service-role/AmazonDMSVPCManagementRole"
  role       = join("", aws_iam_role.dms_vpc_management[*].name)
}

locals {
  enabled = module.this.enabled
}

resource "aws_dms_event_subscription" "default" {
  count = local.enabled ? 1 : 0

  name             = module.this.id
  enabled          = var.event_subscription_enabled
  event_categories = var.event_categories
  source_type      = var.source_type
  source_ids       = var.source_ids
  sns_topic_arn    = var.sns_topic_arn

  tags = module.this.tags
}

resource "aws_iam_role" "replication" {
  name = "s3-bucket-replication-${random_pet.this.id}"

  assume_role_policy = <<POLICY
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Action": "sts:AssumeRole",
      "Principal": {
        "Service": "s3.amazonaws.com"
      },
      "Effect": "Allow",
      "Sid": ""
    }
  ]
}
POLICY
}

resource "aws_iam_policy" "replication" {
  name = "s3-bucket-replication-${random_pet.this.id}"

  policy = <<POLICY
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Action": [
        "s3:GetReplicationConfiguration",
        "s3:ListBucket"
      ],
      "Effect": "Allow",
      "Resource": [
        "arn:aws:s3:::${local.bucket_name}"
      ]
    },
    {
      "Action": [
        "s3:GetObjectVersion",
        "s3:GetObjectVersionAcl"
      ],
      "Effect": "Allow",
      "Resource": [
        "arn:aws:s3:::${local.bucket_name}/*"
      ]
    },
    {
      "Action": [
        "s3:ReplicateObject",
        "s3:ReplicateDelete"
      ],
      "Effect": "Allow",
      "Resource": "arn:aws:s3:::${local.destination_bucket_name}/*"
    }
  ]
}
POLICY
}

resource "aws_iam_policy_attachment" "replication" {
  name       = "s3-bucket-replication-${random_pet.this.id}"
  roles      = [aws_iam_role.replication.name]
  policy_arn = aws_iam_policy.replication.arn
}

################################################################################
# Amazon S3 Vectors Vector Bucket
################################################################################

resource "aws_s3vectors_vector_bucket" "this" {
  count = var.create ? 1 : 0

  vector_bucket_name = var.vector_bucket_name
  force_destroy      = var.force_destroy
  region             = var.region
  tags               = var.tags

  dynamic "encryption_configuration" {
    for_each = var.encryption_configuration != null ? [var.encryption_configuration] : []

    content {
      sse_type    = encryption_configuration.value.sse_type
      kms_key_arn = encryption_configuration.value.kms_key_arn
    }
  }
}

################################################################################
# Amazon S3 Vectors Vector Bucket Policy
################################################################################

resource "aws_s3vectors_vector_bucket_policy" "this" {
  count = var.create && var.create_policy ? 1 : 0

  vector_bucket_arn = aws_s3vectors_vector_bucket.this[0].vector_bucket_arn
  policy            = var.policy
  region            = var.region
}

################################################################################
# Amazon S3 Vectors Index
################################################################################

resource "aws_s3vectors_index" "this" {
  for_each = { for k, v in var.indexes : k => v if var.create }

  index_name         = each.value.index_name
  vector_bucket_name = aws_s3vectors_vector_bucket.this[0].vector_bucket_name

  data_type       = each.value.data_type
  dimension       = each.value.dimension
  distance_metric = each.value.distance_metric
  region          = var.region
  tags            = merge(var.tags, each.value.tags)

  dynamic "encryption_configuration" {
    for_each = each.value.encryption_configuration != null ? [each.value.encryption_configuration] : []

    content {
      sse_type    = encryption_configuration.value.sse_type
      kms_key_arn = encryption_configuration.value.kms_key_arn
    }
  }

  dynamic "metadata_configuration" {
    for_each = each.value.metadata_configuration != null ? [each.value.metadata_configuration] : []

    content {
      non_filterable_metadata_keys = metadata_configuration.value.non_filterable_metadata_keys
    }
  }
}

# The resources defined in this file are only used for demonstrating private connectivity
# They are not required for the solution

locals {
  client_name = "${local.name}-client"
}

################################################################################
# VPC
################################################################################

module "client_vpc" {
  source  = "terraform-aws-modules/vpc/aws"
  version = "~> 5.0"

  name = local.client_name
  cidr = local.vpc_cidr

  azs             = local.azs
  private_subnets = [for k, v in local.azs : cidrsubnet(local.vpc_cidr, 4, k)]
  public_subnets  = [for k, v in local.azs : cidrsubnet(local.vpc_cidr, 4, k + 10)]

  enable_nat_gateway = true
  single_nat_gateway = true

  manage_default_network_acl    = true
  default_network_acl_tags      = { Name = "${local.client_name}-default" }
  manage_default_route_table    = true
  default_route_table_tags      = { Name = "${local.client_name}-default" }
  manage_default_security_group = true
  default_security_group_tags   = { Name = "${local.client_name}-default" }

  tags = merge(local.tags, {
    Name = local.client_name
  })
}

################################################################################
# EC2 Instance
################################################################################

module "client_ec2_instance" {
  source = "terraform-aws-modules/ec2-instance/aws"

  name = local.client_name

  create_iam_instance_profile = true
  iam_role_policies = {
    EKSFullAccess                = aws_iam_policy.eks_full_access_policy.arn
    AmazonSSMManagedInstanceCore = "arn:aws:iam::aws:policy/AmazonSSMManagedInstanceCore"
  }

  vpc_security_group_ids = [module.client_security_group.security_group_id]
  subnet_id              = element(module.client_vpc.private_subnets, 0)

  user_data = <<-EOT
    #!/bin/bash

    # Install kubectl
    curl -LO https://dl.k8s.io/release/v${module.eks.cluster_version}.0/bin/linux/amd64/kubectl
    install -o root -g root -m 0755 kubectl /usr/local/bin/kubectl

    # Remove default awscli which is v1 - we want latest v2
    yum remove awscli -y
    curl "https://awscli.amazonaws.com/awscli-exe-linux-x86_64.zip" -o "awscliv2.zip"
    unzip -qq awscliv2.zip
    ./aws/install
  EOT

  tags = merge(local.tags, {
    Name = local.client_name
  })
}

resource "aws_iam_policy" "eks_full_access_policy" {
  name        = "EKSFullAccess"
  path        = "/"
  description = "EKS full-access policy"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "eks:DescribeCluster",
          "eks:ListClusters"
        ]
        Effect   = "Allow"
        Resource = module.eks.cluster_arn
      },
    ]
  })
}

module "client_security_group" {
  source  = "terraform-aws-modules/security-group/aws"
  version = "~> 5.0"

  name        = local.client_name
  description = "Security group for SSM access to private cluster"
  vpc_id      = module.client_vpc.vpc_id

  egress_with_cidr_blocks = [
    {
      from_port   = 0
      to_port     = 0
      protocol    = "-1"
      cidr_blocks = "0.0.0.0/0"
    },
  ]

  tags = merge(local.tags, {
    Name = local.client_name
  })
}

terraform {
  required_version = ">= 1.0"

  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = ">= 4.47"
    }
    time = {
      source  = "hashicorp/time"
      version = "0.10.0"
    }
    null = {
      source  = "hashicorp/null"
      version = "3.2.2"
    }
  }
}

provider "aws" {
  region = local.region
}

data "terraform_remote_state" "main" {
  backend = "local"


  config = {
    path = "${path.module}/../terraform.tfstate"
  }
}

locals {
  region               = data.terraform_remote_state.main.outputs.region
  cur_bucket_id        = data.terraform_remote_state.main.outputs.cur_bucket_id
  s3_cur_report_prefix = data.terraform_remote_state.main.outputs.s3_cur_report_prefix
}

################################################################################
# Athena
################################################################################

resource "null_resource" "download_file" {
  triggers = {
    always_run = timestamp()
  }

  provisioner "local-exec" {
    command = <<EOT
      if aws s3 ls s3://${local.cur_bucket_id}/${local.s3_cur_report_prefix}/kubecost/crawler-cfn.yml; then
        aws s3 cp s3://${local.cur_bucket_id}/${local.s3_cur_report_prefix}/kubecost/crawler-cfn.yml crawler-cfn.yml
      else
        echo "The crawler-cfn.yml does not exist yet. Come back and run terraform apply again in 24h."
      fi
    EOT
  }
}

resource "time_sleep" "wait_60_seconds" {
  create_duration = "60s"

  depends_on = [null_resource.download_file]
}

resource "aws_cloudformation_stack" "athena_integration" {
  count = fileexists("${path.module}/crawler-cfn.yml") ? 1 : 0

  name          = "kubecost"
  template_body = try(file("${path.module}/crawler-cfn.yml"), null)
  capabilities  = ["CAPABILITY_IAM"]

  depends_on = [null_resource.download_file, time_sleep.wait_60_seconds]
}

################################################################################
# VPC Lattice service network
################################################################################

resource "aws_vpclattice_service_network" "this" {
  name      = "my-services"
  auth_type = "NONE"

  tags = local.tags
}

resource "aws_vpclattice_service_network_vpc_association" "cluster_vpc" {
  vpc_identifier             = module.cluster_vpc.vpc_id
  service_network_identifier = aws_vpclattice_service_network.this.id
}

resource "aws_vpclattice_service_network_vpc_association" "client_vpc" {
  vpc_identifier             = module.client_vpc.vpc_id
  service_network_identifier = aws_vpclattice_service_network.this.id
}

resource "time_sleep" "wait_for_lattice_resources" {
  depends_on = [helm_release.demo_application]

  create_duration = "120s"
}

################################################################################
# Custom domain name for VPC lattice service
# Records will be created by external-dns using DNSEndpoint objects which
# are created by the VPC Lattice gateway api controller when creating HTTPRoutes
################################################################################

resource "aws_route53_zone" "primary" {
  name = "example.com"

  vpc {
    vpc_id = module.client_vpc.vpc_id
  }

  tags = local.tags
}

provider "aws" {
  region = local.region
}

locals {
  name   = "vpc-lattice"
  region = "us-west-2"

  domain = var.custom_domain_name

  tags = {
    Blueprint  = local.name
    GithubRepo = "github.com/aws-ia/terraform-aws-eks-blueprints"
  }
}

#-------------------------------
# Create Private Hosted Zone
#-------------------------------

resource "aws_route53_zone" "private_zone" {
  name = local.domain

  vpc {
    vpc_id = aws_vpc.example.id
  }

  #we will add vpc association in other terraform stack, prevent this one to revert this
  lifecycle {
    ignore_changes = [
      vpc,
    ]
  }

  force_destroy = true
  tags          = local.tags
}

#dummy VPC that will not be used, but needed to create private hosted zone
resource "aws_vpc" "example" {
  cidr_block = "10.0.0.0/16"

  tags = {
    Name = "Example VPC"
  }
}

################################################################################
# Create IAM role to talk to VPC Lattice services and get Certificate from Manager
################################################################################
data "aws_iam_policy_document" "eks_assume" {
  statement {
    effect = "Allow"
    principals {
      type        = "Service"
      identifiers = ["pods.eks.amazonaws.com"]
    }
    actions = ["sts:AssumeRole", "sts:TagSession"]
  }
}
resource "aws_iam_role" "vpc_lattice_role" {
  name               = "${local.name}-sigv4-client"
  description        = "IAM role for aws-sigv4-client VPC Lattice access"
  assume_role_policy = data.aws_iam_policy_document.eks_assume.json
}

resource "aws_iam_role_policy_attachment" "vpc_lattice_invoke_access" {
  role       = aws_iam_role.vpc_lattice_role.name
  policy_arn = "arn:aws:iam::aws:policy/VPCLatticeServicesInvokeAccess"
}

resource "aws_iam_role_policy_attachment" "private_ca_read_only" {
  role       = aws_iam_role.vpc_lattice_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSCertificateManagerPrivateCAReadOnly"
}

#-------------------------------
# Associates a certificate with an AWS Certificate Manager Private Certificate Authority (ACM PCA Certificate Authority).
# An ACM PCA Certificate Authority is unable to issue certificates until it has a certificate associated with it.
# A root level ACM PCA Certificate Authority is able to self-sign its own root certificate.
#-------------------------------

# # https://docs.aws.amazon.com/acm-pca/latest/userguide/pca-rbp.html

resource "aws_acmpca_certificate_authority" "this" {
  enabled = true
  type    = "ROOT"

  certificate_authority_configuration {
    key_algorithm     = "RSA_4096"
    signing_algorithm = "SHA512WITHRSA"

    subject {
      common_name  = var.custom_domain_name
      organization = var.organization
    }
  }

  permanent_deletion_time_in_days = 7

  tags = local.tags
}

resource "aws_acmpca_certificate" "this" {
  certificate_authority_arn   = aws_acmpca_certificate_authority.this.arn
  certificate_signing_request = aws_acmpca_certificate_authority.this.certificate_signing_request
  signing_algorithm           = "SHA512WITHRSA"

