module "firehose_to_s3_iam_role" {
  source  = "terraform-aws-modules/iam/aws//modules/iam-role"
  version = "~> 6.0"

  name = "${random_pet.this.id}-firehose-to-s3-"

  trust_policy_permissions = {
    TrustRoleAndServiceToAssume = {
      actions = [
        "sts:AssumeRole",
        "sts:TagSession",
      ]
      principals = [{
        type = "Service"
        identifiers = [
          "firehose.amazonaws.com"
        ]
      }]
    }
  }

  create_inline_policy = true
  inline_policy_permissions = {
    FirehoseToS3 = {
      actions = [
        "s3:AbortMultipartUpload",
        "s3:GetBucketLocation",
        "s3:GetObject",
        "s3:ListBucket",
        "s3:ListBucketMultipartUploads",
        "s3:PutObject",
      ]
      resources = [
        module.logs_bucket.s3_bucket_arn,
        "${module.logs_bucket.s3_bucket_arn}/*",
      ]
    }
  }
}

module "cw_logs_to_firehose_iam_role" {
  source  = "terraform-aws-modules/iam/aws//modules/iam-role"
  version = "~> 6.0"

  name = "${random_pet.this.id}-cw-logs-to-firehose-"

  trust_policy_permissions = {
    TrustRoleAndServiceToAssume = {
      actions = [
        "sts:AssumeRole",
        "sts:TagSession",
      ]
      principals = [{
        type = "Service"
        identifiers = [
          "logs.amazonaws.com"
        ]
      }]
    }
  }

  create_inline_policy = true
  inline_policy_permissions = {
    CwLogsToFirehose = {
      actions = [
        "firehose:PutRecord",
      ]
      resources = [
        aws_kinesis_firehose_delivery_stream.logs.arn,
      ]
    }
  }
}

