# -----------------------------------------------------------------------------
# Self-signed CA for testing mTLS
# -----------------------------------------------------------------------------

resource "tls_private_key" "ca" {
  algorithm = "RSA"
  rsa_bits  = 2048
}

resource "tls_self_signed_cert" "ca" {
  private_key_pem = tls_private_key.ca.private_key_pem

  subject {
    common_name  = "Test CA"
    organization = "Test"
  }

  validity_period_hours = 8760
  is_ca_certificate     = true

  allowed_uses = [
    "cert_signing",
    "crl_signing",
  ]
}

# -----------------------------------------------------------------------------
# S3 bucket for the CA cert bundle (trust store source)
# -----------------------------------------------------------------------------

resource "random_id" "this" {
  byte_length = 4
}

resource "aws_s3_bucket" "certs" {
  bucket = "mtls-example-certs-${random_id.this.hex}"
}

resource "aws_s3_bucket_public_access_block" "certs" {
  bucket = aws_s3_bucket.certs.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

resource "aws_s3_object" "ca_bundle" {
  bucket  = aws_s3_bucket.certs.id
  key     = "ca-bundle.pem"
  content = tls_self_signed_cert.ca.cert_pem
}

# -----------------------------------------------------------------------------
# CloudFront Trust Store
# -----------------------------------------------------------------------------

resource "aws_cloudfront_trust_store" "this" {
  name = "mtls-example-${random_id.this.hex}"

  ca_certificates_bundle_source {
    ca_certificates_bundle_s3_location {
      bucket = aws_s3_bucket.certs.id
      key    = aws_s3_object.ca_bundle.key
      region = var.region
    }
  }

  depends_on = [aws_s3_object.ca_bundle]
}

# -----------------------------------------------------------------------------
# CloudFront CDN with mTLS enabled
# -----------------------------------------------------------------------------

module "cdn_mtls" {
  source = "../../"

  origin_domain_name = var.origin_domain_name
  origin_type        = "custom"
  logging_enabled    = var.logging_enabled

  viewer_mtls_config = {
    mode                           = "required"
    trust_store_id                 = aws_cloudfront_trust_store.this.id
    advertise_trust_store_ca_names = true
    ignore_certificate_expiry      = false
  }

  context = module.this.context
}

# -----------------------------------------------------------------------------
# CloudFront CDN without mTLS (verify no-op when not configured)
# -----------------------------------------------------------------------------

module "cdn_no_mtls" {
  source = "../../"

  origin_domain_name = var.origin_domain_name
  origin_type        = "custom"
  logging_enabled    = var.logging_enabled

  context = module.this.context
}

provider "aws" {
  region = var.region
}

resource "aws_cloudfront_origin_access_identity" "oai" {
  comment = "Managed by Terraform"
}

module "website" {
  source = "../../"

  origin_domain_name = var.origin_domain_name
  custom_origins = [
    {
      domain_name = "assets.s3.us-east-1.amazonaws.com"
      origin_id   = "assets"
      s3_origin_config = {
        origin_access_identity = aws_cloudfront_origin_access_identity.oai.cloudfront_access_identity_path
      }
    }
  ]

  ordered_cache = [
    {
      target_origin_id = "assets"
      path_pattern     = "/static/*"
    }
  ]

  logging_enabled = var.logging_enabled
  context         = module.this.context
}

module "api" {
  source = "../../"

  origin_domain_name = var.origin_domain_name
  origin_shield = {
    enabled = true
    region  = "us-east-1"
  }

  custom_origins = [
    {
      domain_name           = "api.example.com"
      origin_id             = "grpc"
      https_port            = 443
      origin_protocl_policy = "https-only"
      origin_ssl_protocols  = ["TLSv1.2"]
      custom_origin_config = {
        origin_keepalive_timeout = 15
        origin_read_timeout      = 45
      }
    }
  ]

  custom_error_response = [
    {
      error_code = 404
    },
    {
      error_caching_min_ttl = 10
      error_code            = 403
      response_code         = 404
      response_page_path    = "/errors/404.html"
    }
  ]

  ordered_cache = [
    {
      target_origin_id = "grpc"
      path_pattern     = "/UserService/*"
      allowed_methods  = ["DELETE", "GET", "HEAD", "OPTIONS", "PATCH", "POST", "PUT"]
      min_ttl          = 0
      default_ttl      = 0
      max_ttl          = 0
      grpc_config = {
        enabled = true
      }
    }
  ]

  logging_enabled = var.logging_enabled
  context         = module.this.context
}

# Cloudfront distribution for main s3 site.
resource "aws_cloudfront_distribution" "alb_distribution" {
  origin {
    domain_name = aws_alb.alb_external.dns_name
    origin_id   = aws_alb.alb_external.dns_name

    custom_origin_config {
      http_port              = 80
      https_port             = 443
      origin_protocol_policy = "http-only"
      origin_ssl_protocols   = ["TLSv1.2"]
    }
  }

  enabled         = true
  is_ipv6_enabled = false
  price_class     = "PriceClass_100" # Use only North America and Europe

  default_cache_behavior {
    allowed_methods  = ["GET", "HEAD", "PUT", "POST", "PATCH", "OPTIONS", "DELETE"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = aws_alb.alb_external.dns_name

    forwarded_values {
      query_string = true
      headers      = ["Host", "Accept", "Origin"]

      cookies {
        forward = "all"
      }
    }

    viewer_protocol_policy = "redirect-to-https"
    compress               = true
  }

  restrictions {
    geo_restriction {
      restriction_type = "none"
    }
  }

  web_acl_id = var.acl_id

  viewer_certificate {
    cloudfront_default_certificate = true
  }

  tags = {
    Terraform = "true"
  }
}

