  tags = {
    Name        = "Magento Files"
    Description = "S3 bucket for Magento"
    Terraform   = true
  }

  server_side_encryption_configuration {
    rule {
      apply_server_side_encryption_by_default {
        sse_algorithm = "AES256"
      }
    }
  }
}


resource "aws_s3_bucket_policy" "magento_files" {
