{
    "Version": "2012-10-17",
    "Statement": [
        {
            "Sid": "AllowEC2toS3",
            "Effect": "Allow",
            "Principal": "*",
            "Action": "s3:*",
            "Resource": "arn:aws:s3:::${aws_s3_bucket.magento_files.bucket}/*",
