# --- examples/single_vpc_logging/policy.tf ---

resource "aws_networkfirewall_firewall_policy" "anfw_policy" {
  name = "policy-firewall-${var.identifier}"

  firewall_policy {

    # Stateless configuration
    stateless_default_actions          = ["aws:forward_to_sfe"]
    stateless_fragment_default_actions = ["aws:forward_to_sfe"]

    stateless_rule_group_reference {
      priority     = 10
      resource_arn = aws_networkfirewall_rule_group.drop_remote.arn
    }

    # Stateful configuration
    stateful_engine_options {
      rule_order = "STRICT_ORDER"
    }
    stateful_default_actions = ["aws:drop_strict", "aws:alert_strict"]
    stateful_rule_group_reference {
      priority     = 10
      resource_arn = aws_networkfirewall_rule_group.allow_icmp.arn
    }
    stateful_rule_group_reference {
      priority     = 20
      resource_arn = aws_networkfirewall_rule_group.allow_domains.arn
    }
  }
}

# Stateless Rule Group - Dropping any SSH or RDP connection
resource "aws_networkfirewall_rule_group" "drop_remote" {
  capacity = 2
  name     = "drop-remote-${var.identifier}"
  type     = "STATELESS"
  rule_group {
    rules_source {
      stateless_rules_and_custom_actions {

        stateless_rule {
          priority = 1
          rule_definition {
            actions = ["aws:drop"]
            match_attributes {
              protocols = [6]
              source {
                address_definition = "0.0.0.0/0"
              }
              source_port {
                from_port = 22
                to_port   = 22
              }
              destination {
                address_definition = "0.0.0.0/0"
              }
              destination_port {
                from_port = 22
                to_port   = 22
              }
            }
          }
        }

        stateless_rule {
          priority = 2
          rule_definition {
            actions = ["aws:drop"]
            match_attributes {
              protocols = [27]
              source {
                address_definition = "0.0.0.0/0"
              }
              destination {
                address_definition = "0.0.0.0/0"
              }
            }
          }
        }
      }
    }
  }
}

# Stateful Rule Group 1 - Allowing ICMP traffic
resource "aws_networkfirewall_rule_group" "allow_icmp" {
  capacity = 100
  name     = "allow-icmp-${var.identifier}"
  type     = "STATEFUL"
  rule_group {
    rules_source {
      rules_string = <<EOF
      pass icmp any any -> any any (msg: "Allowing ICMP packets"; sid:2; rev:1;)
      EOF
    }
    stateful_rule_options {
      rule_order = "STRICT_ORDER"
    }
  }
}

# Stateful Rule Group 2 - Allowing access to .amazon.com (HTTPS)
resource "aws_networkfirewall_rule_group" "allow_domains" {
  capacity = 100
  name     = "allow-domains-${var.identifier}"
  type     = "STATEFUL"
  rule_group {
    rules_source {
      rules_string = <<EOF
      pass tcp any any <> $EXTERNAL_NET 443 (msg:"Allowing TCP in port 443"; flow:not_established; sid:892123; rev:1;)
      pass tls any any -> $EXTERNAL_NET 443 (tls.sni; dotprefix; content:".amazon.com"; endswith; msg:"Allowing .amazon.com HTTPS requests"; sid:892125; rev:1;)
      EOF
    }
    stateful_rule_options {
      rule_order = "STRICT_ORDER"
    }
  }
}

# --- modules/logging/main.tf ---
locals {
  log_type_lookup = {
    alert_log = "ALERT",
    flow_log  = "FLOW"
  }

  log_destination_lookup = {
    s3_bucket        = "S3",
    cloudwatch_logs  = "CloudWatchLogs",
    kinesis_firehose = "KinesisDataFirehose"
  }

  log_destination_params = {
    alert_log = {
      s3_bucket = {
        bucketName = try(var.logging_configuration.alert_log.s3_bucket.bucketName, null)
        prefix     = try(var.logging_configuration.alert_log.s3_bucket.logPrefix, null)
      }
      cloudwatch_logs = {
        logGroup = try(var.logging_configuration.alert_log.cloudwatch_logs.logGroupName, null)
      }
      kinesis_firehose = {
        deliveryStream = try(var.logging_configuration.alert_log.kinesis_firehose.deliveryStreamName, null)
      }
    }

    flow_log = {
      s3_bucket = {
        bucketName = try(var.logging_configuration.flow_log.s3_bucket.bucketName, null)
        prefix     = try(var.logging_configuration.flow_log.s3_bucket.logPrefix, null)
      }
      cloudwatch_logs = {
        logGroup = try(var.logging_configuration.flow_log.cloudwatch_logs.logGroupName, null)
      }
      kinesis_firehose = {
        deliveryStream = try(var.logging_configuration.flow_log.kinesis_firehose.deliveryStreamName, null)
      }
    }

  }
}

resource "aws_networkfirewall_logging_configuration" "anfw_logs" {
  firewall_arn = var.firewall_arn
  logging_configuration {
    dynamic "log_destination_config" {
      for_each = var.logging_configuration
      content {
        log_type             = local.log_type_lookup[log_destination_config.key]
        log_destination_type = local.log_destination_lookup[keys(log_destination_config.value)[0]]
        log_destination      = local.log_destination_params[log_destination_config.key][keys(log_destination_config.value)[0]]
      }
    }
  }
}

