terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "= 4.2"
    }
  }
}

variable "cidr" {
  default = "10.0.0.0/8"
}

locals {
  cidr = "10.0.0.0/8"
  # regional_cidrs = cidrsubnets(var.cidr, 8, 8, 8, 8)
}

module "ipv4_scope" {
  # source  = "aws-ia/ipam/aws"
  source = "../.."

  top_cidr = [var.cidr]

  pool_configurations = {
    us-west-2 = {
      cidr   = ["10.0.0.0/16"] # [local.regional_cidrs[0], local.regional_cidrs[1]]
      locale = "us-west-2"

      sub_pools = {
        sandbox = {
          cidr = ["10.0.0.0/20"]
          allocation_resource_tags = {
            env = "sandbox"
          }
        }
      }
    }
  }
}

resource "aws_vpc_ipam_scope" "scope_for_overlapping_cidr" {
  ipam_id     = module.ipv4_scope.ipam_info.id
  description = "Second private scope for overlapping cidr."
}

module "overlapping_cidr_second_ipv4_scope" {
  # source  = "aws-ia/ipam/aws"
  source = "../.."

  top_cidr      = [var.cidr]
  create_ipam   = false
  ipam_scope_id = aws_vpc_ipam_scope.scope_for_overlapping_cidr.id

  pool_configurations = {
    us-east-1 = {
      name        = "ipv6 us-east-1"
      description = "pool for ipv6 us-east-1"
      cidr        = "10.0.0.0/16" #[local.regional_cidrs[0]]
      locale      = "us-east-1"
    }
    us-west-2 = {
      description = "pool for ipv6 us-west-2"
      cidr        = "10.0.1.0/16" #[local.regional_cidrs[1]]
      locale      = "us-west-2"
    }
  }
}

locals {
  description = var.pool_config.description == null ? replace(var.implied_description, "/", "-") : var.pool_config.description

  name = var.pool_config.name == null ? var.implied_name : var.pool_config.name
  tags = merge(var.pool_config.tags, {
    Name = local.name }
  )

  ram_share_enabled = try(length(var.pool_config.ram_share_principals), 0) > 0
  pool_cidrs        = var.pool_config.cidr == null ? [var.pool_config.netmask_length] : var.pool_config.cidr
  cidr_authorization_contexts = {
    for k, v in var.cidr_authorization_contexts : v.cidr => {
      message   = v.message,
      signature = v.signature
    }
  }
}

resource "aws_vpc_ipam_pool" "sub" {
  address_family      = var.address_family
  ipam_scope_id       = var.ipam_scope_id
  source_ipam_pool_id = var.source_ipam_pool_id

  description                       = local.description
  locale                            = var.implied_locale != "None" ? var.implied_locale : var.pool_config.locale
  allocation_default_netmask_length = var.pool_config.allocation_default_netmask_length
  allocation_max_netmask_length     = var.pool_config.allocation_max_netmask_length
  allocation_min_netmask_length     = var.pool_config.allocation_min_netmask_length
  allocation_resource_tags          = var.pool_config.allocation_resource_tags
  auto_import                       = var.pool_config.auto_import
  aws_service                       = var.pool_config.aws_service
  publicly_advertisable             = var.pool_config.publicly_advertisable
  public_ip_source                  = var.pool_config.public_ip_source

  tags = local.tags
}

resource "aws_vpc_ipam_pool_cidr" "sub" {
  for_each = toset(local.pool_cidrs)

  ipam_pool_id   = aws_vpc_ipam_pool.sub.id
  cidr           = length(regexall("/", each.key)) > 0 ? each.key : null
  netmask_length = length(regexall("/", each.key)) == 0 ? each.key : null

  dynamic "cidr_authorization_context" {
    for_each = length(var.cidr_authorization_contexts) == 0 ? [] : [1]
    content {
      message   = local.cidr_authorization_contexts[each.key].message
      signature = local.cidr_authorization_contexts[each.key].signature
    }
  }
}

resource "aws_ram_resource_share" "sub" {
  count = local.ram_share_enabled ? 1 : 0

  # if a user specifies a var.pool.description must validate there is no / which is invalid for RAM names
  name = replace(local.description, "/", "-")

  tags = local.tags
}

resource "aws_ram_resource_association" "sub" {
  count = local.ram_share_enabled ? 1 : 0

  resource_arn       = aws_vpc_ipam_pool.sub.arn
  resource_share_arn = aws_ram_resource_share.sub[0].arn
}

resource "aws_ram_principal_association" "sub" {
  for_each = local.ram_share_enabled ? toset(var.pool_config.ram_share_principals) : []

  principal          = each.key
  resource_share_arn = aws_ram_resource_share.sub[0].arn
}

resource "aws_kms_key" "vmseries" {
  description         = "vmseries disk encryption key"
  enable_key_rotation = true
}

resource "aws_kms_alias" "vmseries" {
  name          = "alias/vmseries"
  target_key_id = aws_kms_key.vmseries.key_id
}


module "security_vpc" {
  source = "PaloAltoNetworks/vmseries-modules/aws//modules/vpc"

  name                    = var.security_vpc_name
  cidr_block              = var.security_vpc_cidr
  security_groups         = var.security_vpc_security_groups
  create_internet_gateway = true
  enable_dns_hostnames    = true
  enable_dns_support      = true
  instance_tenancy        = "default"
}

module "security_subnet_sets" {
  source = "PaloAltoNetworks/vmseries-modules/aws//modules/subnet_set"

  for_each = toset(distinct([for _, v in var.security_vpc_subnets : v.set]))

  name                = each.key
  vpc_id              = module.security_vpc.id
  has_secondary_cidrs = module.security_vpc.has_secondary_cidrs
  cidrs               = { for k, v in var.security_vpc_subnets : k => v if v.set == each.key }
}

module "vmseries" {
  for_each = var.vmseries
  source   = "../../"

  name              = var.name
  ssh_key_name      = var.ssh_key_name
  bootstrap_options = var.bootstrap_options
  ebs_kms_key_alias = aws_kms_alias.vmseries.name

  interfaces = {
    mgmt = {
      device_index       = 0
      security_group_ids = [module.security_vpc.security_group_ids["vmseries_mgmt"]]
      source_dest_check  = true
      subnet_id          = module.security_subnet_sets["mgmt"].subnets[each.value.az].id
      create_public_ip   = true
    }
    public = {
      device_index       = 1
      security_group_ids = [module.security_vpc.security_group_ids["vmseries_public"]]
      source_dest_check  = false
      subnet_id          = module.security_subnet_sets["public"].subnets[each.value.az].id
      create_public_ip   = true
    }
    private = {
      device_index       = 2
      security_group_ids = [module.security_vpc.security_group_ids["vmseries_private"]]
      source_dest_check  = false
      subnet_id          = module.security_subnet_sets["private"].subnets[each.value.az].id
      create_public_ip   = false
    }
  }

  tags = var.global_tags

  depends_on = [
    aws_kms_alias.vmseries
  ]
}

locals {
  security_vpc_routes = concat(
    [for cidr in var.security_vpc_routes_outbound_destin_cidrs :
      {
        subnet_key   = "mgmt"
        next_hop_set = module.security_vpc.igw_as_next_hop_set
        to_cidr      = cidr
      }
    ],
    [
      for cidr in var.security_vpc_routes_outbound_destin_cidrs :
      {
        subnet_key   = "public"
        next_hop_set = module.security_vpc.igw_as_next_hop_set
        to_cidr      = cidr
      }
    ],
  )
}

module "security_vpc_routes" {
  for_each = { for route in local.security_vpc_routes : "${route.subnet_key}_${route.to_cidr}" => route }
  source   = "PaloAltoNetworks/vmseries-modules/aws//modules/vpc_route"

  route_table_ids = module.security_subnet_sets[each.value.subnet_key].unique_route_table_ids
  to_cidr         = each.value.to_cidr
  next_hop_set    = each.value.next_hop_set
}

locals {
  enabled                           = module.this.enabled
  zone_name                         = var.zone_name == "" ? "${var.domain_name}." : var.zone_name
  process_domain_validation_options = local.enabled && var.process_domain_validation_options && var.validation_method == "DNS"
  domain_validation_options_set     = local.process_domain_validation_options ? aws_acm_certificate.default[0].domain_validation_options : toset([])
  public_enabled                    = var.certificate_authority_arn == null
  private_enabled                   = !local.public_enabled
}

resource "aws_acm_certificate" "default" {
  count = local.enabled ? 1 : 0

  domain_name               = var.domain_name
  validation_method         = local.public_enabled ? var.validation_method : null
  subject_alternative_names = var.subject_alternative_names
  certificate_authority_arn = var.certificate_authority_arn
  key_algorithm             = var.key_algorithm

  options {
    certificate_transparency_logging_preference = var.certificate_transparency_logging_preference ? "ENABLED" : "DISABLED"
    export                                      = var.certificate_export ? "ENABLED" : "DISABLED"
  }

  tags = module.this.tags

  lifecycle {
    create_before_destroy = true
  }
}

data "aws_route53_zone" "default" {
  count        = local.process_domain_validation_options ? 1 : 0
  zone_id      = var.zone_id
  name         = try(length(var.zone_id), 0) == 0 ? local.zone_name : null
  private_zone = local.private_enabled
}

resource "aws_route53_record" "default" {
  for_each = {
    for dvo in local.domain_validation_options_set : dvo.domain_name => {
      name   = dvo.resource_record_name
      record = dvo.resource_record_value
      type   = dvo.resource_record_type
    }
  }
  zone_id         = join("", data.aws_route53_zone.default.*.zone_id)
  ttl             = var.ttl
  allow_overwrite = true
  name            = each.value.name
  type            = each.value.type
  records         = [each.value.record]
}

resource "aws_acm_certificate_validation" "default" {
  count                   = local.process_domain_validation_options && var.wait_for_certificate_issued ? 1 : 0
  certificate_arn         = join("", aws_acm_certificate.default[*].arn)
  validation_record_fqdns = [for record in aws_route53_record.default : record.fqdn]
}

